svg.script:
(function() {
  var isDark = false; // §2 — declared before build
  var svg    = document.getElementById('root');
  var cont   = document.getElementById('container');
  var items  = Array.prototype.slice.call(document.querySelectorAll('.item'));
  var ns     = 'http://www.w3.org/2000/svg';

  // §5 Depth-Tinting (verbatim from spec)
  var _probe = null;
  function probeColor(cls) {
    if (!_probe) {
      _probe = document.createElementNS(ns, 'rect');
      _probe.style.visibility = 'hidden';
      _probe.style.position   = 'absolute';
      svg.appendChild(_probe);
    }
    _probe.setAttribute('class', cls);
    var fill = window.getComputedStyle(_probe).fill;
    var m = fill.match(/[\d.]+/g);
    return m ? [+m[0], +m[1], +m[2]] : [0, 0, 0];
  }
  function blendRgb(base, bgHex, t) {
    var bg = hexToRgb(bgHex);
    return 'rgb(' + [0,1,2].map(function(i) {
      return Math.round(base[i] + (bg[i] - base[i]) * t);
    }).join(',') + ')';
  }
  function hexToRgb(h) {
    var n = parseInt(h.replace('#',''), 16);
    return [(n>>16)&255, (n>>8)&255, n&255];
  }
  function cssVar(name) {
    return window.getComputedStyle(svg).getPropertyValue(name).trim();
  }
  function getTint(ci, depth) {
    var base = probeColor('bar-' + ci);
    var t    = parseFloat(cssVar('--blend-d' + Math.min(depth, 4)));
    var bg   = cssVar(isDark ? '--bg-dark' : '--bg-light');
    return blendRgb(base, bg, t);
  }
  function recolor() {
    items.forEach(function(el) {
      el.querySelector('circle').setAttribute('fill',
        getTint(el.getAttribute('data-ci'), el.getAttribute('data-depth')));
    });
  }

  // §3 Method A1 animation — stagger 0.25s, duration 0.8s (matches bar chart)
  var lastDelay = (items.length - 1) * 0.25;
  items.forEach(function(el, i) {
    el.style.animation = 'itemFade 0.8s ease-out ' + (i * 0.25) + 's';
    el.addEventListener('animationend', function() {
      el.style.animation = 'none';
      el.classList.add('visible');
    }, { once: true });
  });
  setTimeout(function() { cont.classList.add('ready'); }, (lastDelay + 0.8 + 0.1) * 1000);

  // §4 JS-driven tooltip
  var tip    = document.getElementById('tip');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');
  var tipBdr = document.getElementById('tip-bdr');
  var tipArr = document.getElementById('tip-arr');
  var tipBgF = document.getElementById('tip-bg-fill');

  function showTip(el) {
    var circle = el.querySelector('circle');
    var cx = parseFloat(circle.getAttribute('cx'));
    var cy = parseFloat(circle.getAttribute('cy'));
    var r  = parseFloat(circle.getAttribute('r'));

    var val = el.getAttribute('data-val');
    var lbl = el.getAttribute('data-lbl');
    var pct = el.getAttribute('data-pct');

    tipVal.textContent = val;
    tipLbl.textContent = lbl + ' · ' + pct;

    // Measure actual rendered text widths
    var pad = 20, bh = 42, tail = 8, rx = 9;
    var valW = tipVal.getBBox().width + pad;
    var lblW = tipLbl.getBBox().width + pad;
    var hw   = Math.max(valW, lblW, 60) / 2;

    // Position: bubble sits above circle, arrow tip touches circle top
    var tx = Math.max(hw + 8, Math.min(cx, 1100 - hw - 8));
    var ty = cy - r - tail - bh - 4;
    var flip = ty < 90;
    if (flip) ty = cy + r + tail + 4;

    // Background fill
    tipBgF.setAttribute('x', -hw);
    tipBgF.setAttribute('y', 0);
    tipBgF.setAttribute('width',  hw * 2);
    tipBgF.setAttribute('height', bh);

    // Border + integrated tail arrow
    var l = -hw, r2 = hw, t2 = 0, b2 = bh;
    if (!flip) {
      tipBdr.setAttribute('d',
        'M'+(l+rx)+','+t2+' L'+(r2-rx)+','+t2+
        ' Q'+r2+','+t2+' '+r2+','+(t2+rx)+
        ' L'+r2+','+(b2-rx)+
        ' Q'+r2+','+b2+' '+(r2-rx)+','+b2+
        ' L8,'+b2+' L0,'+(b2+tail)+' L-8,'+b2+
        ' L'+(l+rx)+','+b2+
        ' Q'+l+','+b2+' '+l+','+(b2-rx)+
        ' L'+l+','+(t2+rx)+
        ' Q'+l+','+t2+' '+(l+rx)+','+t2+' Z'
      );
    } else {
      tipBdr.setAttribute('d',
        'M'+(l+rx)+','+t2+' L-8,'+t2+' L0,'+(t2-tail)+' L8,'+t2+
        ' L'+(r2-rx)+','+t2+
        ' Q'+r2+','+t2+' '+r2+','+(t2+rx)+
        ' L'+r2+','+(b2-rx)+
        ' Q'+r2+','+b2+' '+(r2-rx)+','+b2+
        ' L'+(l+rx)+','+b2+
        ' Q'+l+','+b2+' '+l+','+(b2-rx)+
        ' L'+l+','+(t2+rx)+
        ' Q'+l+','+t2+' '+(l+rx)+','+t2+' Z'
      );
    }
    tipArr.setAttribute('d', '');

    tipVal.setAttribute('x', 0);
    tipVal.setAttribute('y', bh * 0.38);
    tipLbl.setAttribute('x', 0);
    tipLbl.setAttribute('y', bh * 0.72);

    tip.setAttribute('transform', 'translate('+tx+','+ty+')');
    tip.style.opacity = '1';
  }

  function hideTip() { tip.style.opacity = ''; }

  // §4 Hover interaction
  items.forEach(function(el) {
    el.addEventListener('mouseenter', function() {
      cont.classList.add('hovering');
      items.forEach(function(x) { x.classList.remove('hovered'); });
      el.classList.add('hovered');
      showTip(el);
    });
    el.addEventListener('mouseleave', function() {
      cont.classList.remove('hovering');
      el.classList.remove('hovered');
      hideTip();
    });
  });

  // §2 Dark mode toggle
  function setMode(wantDark) {
    if (wantDark === isDark) return;
    isDark = wantDark;
    var thumb = document.getElementById('tthumb');
    var lbl   = document.getElementById('tlabel');
    if (wantDark) {
      svg.classList.add('dark');
      if (thumb) thumb.setAttribute('cx', '52');
      if (lbl)   lbl.textContent = 'Light';
    } else {
      svg.classList.remove('dark');
      if (thumb) thumb.setAttribute('cx', '16');
      if (lbl)   lbl.textContent = 'Dark';
    }
    recolor();
  }

  document.getElementById('dark-toggle').addEventListener('click', function() { setMode(!isDark); });
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print'; }
  });

  window.setMode = setMode;
  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'setMode') setMode(e.data.dark);
  });

  recolor();
  setMode(window.location.href.indexOf('theme=dark') !== -1);
})();
